import{_ as e,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"24. Rotations Between Hospitals","description":"","frontmatter":{"title":"24. Rotations Between Hospitals","eba":"Doctors in Training 2022-2026","topics":["employment","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/24-rotations-between-hospitals.md","filePath":"ebas/doctors-in-training/doctor-employment/24-rotations-between-hospitals.md"}'),i={name:"ebas/doctors-in-training/doctor-employment/24-rotations-between-hospitals.md"};function r(s,t,l,p,c,h){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="_24-rotations-between-hospitals" tabindex="-1">24. Rotations Between Hospitals <a class="header-anchor" href="#_24-rotations-between-hospitals" aria-label="Permalink to &quot;24. Rotations Between Hospitals&quot;">​</a></h1><p><strong>24.1</strong> The provisions of this clause 24 are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/preliminary/9-nature-of-relationship.html">clause 9</a> (Nature of Relationships), the relevant definitions in <a href="/eba/ebas/doctors-in-training/preliminary/3-definitions.html">clause 3</a> (Parent Hospital, Rotation Hospital, Rotation) and the allowances in <a href="/eba/ebas/doctors-in-training/allowances/52-rotation-allowances.html">clause 52</a> (Rotation Allowances).</p><p><strong>24.2</strong> A Parent Hospital may rotate a Doctor to work at another Hospital (the Rotation Hospital) as part of their structured training program or to meet service demands. For the duration of any such Rotation, the Doctor remains an Employee of the Parent Hospital.</p><p><strong>24.3</strong> A Rotation must be agreed either at the time of the Rotation or at the time of initial appointment. Any single Rotation is typically for a period of 13 weeks. However, the length of any single Rotation may be varied if the position is so advertised or otherwise by agreement.</p><p><strong>24.4</strong> Where, as part of a “rotation” arrangement a Doctor is required to move residence:</p><p><strong>(a)</strong> The Doctor must be provided with a minimum of a whole calendar day clear from duty (including on-call and overtime) between their final shift at Hospital 1 and their first shift at Hospital 2.</p><p>For example: Final shift ceases at Hospital 1 on Saturday at 10:00pm; Whole Calendar Day clear from Duty on Sunday; First shift commences at Hospital 2 on Monday at 8:00am.</p><p><strong>(b)</strong> Notwithstanding 24.4(a) above, where the Doctor is required to perform night shift as their final shift or otherwise performs on-call period, the Doctor must be provided 48 hours break between completing their night shift/on-call period at Hospital 1 and their first shift at Hospital 2.</p><p><strong>(c)</strong> To jointly plan the transition of a Doctor between Hospital 1 and Hospital 2 to achieve the obligations prescribed above, engagement and cooperation must occur between the two hospitals prior to the final roster being issued and contemplate:</p><p><strong>(i)</strong> Appropriate rostered ordinary hours coverage in Hospital 1 and Hospital</p><p><strong>(ii)</strong> Appropriate on-call coverage</p><p><strong>(iii)</strong> Appropriate skill-mix for coverage</p><p><strong>(iv)</strong> Accommodation arrangements including contingency</p><p><strong>(v)</strong> Reasonable time for the Doctor to relocate, including time to rest following their final shift, vacate their accommodation and travel to their next Hospital and appropriate time to settle in and orientate to their new location.</p><p><strong>(d)</strong> Where, due to unforeseeable circumstances, a Doctor is required to perform work beyond the time jointly agreed, appropriate overnight accommodation will be provided to the Doctor if the original accommodation is unavailable.</p><p><strong>24.5</strong> A Rotation may include a rotation to, but not from, an interstate hospital. In this case, a Rotation must only occur as part of the formally agreed training program and the doctor must commence the year with the Parent Hospital, and return to the Parent Hospital before the end of the year.</p><p><strong>24.6</strong> The Parent Hospital must not rotate a Doctor to a Rotation Hospital that does not make available to Doctors a library and other usual study aids of a standard acceptable to the Post Graduate Medical Council of Victoria.</p><p><strong>24.7</strong> During the period of Rotation, the Rotation Hospital is responsible for the payment of wages and entitlements accruing to the Doctor under the Agreement. This is an administrative arrangement between Hospitals and does not affect the Doctor’s employment status under subclause 24.2 above.</p><p><strong>24.8</strong> The Rotation Hospital and the Parent Hospital may agree either:</p><p><strong>(a)</strong> that the Rotation Hospital pay all wages, allowances and utilised accrued entitlements directly to the Doctor; or</p><p><strong>(b)</strong> that the Rotation Hospital remits payment of all wages and entitlements in respect of the Doctor to the Parent Hospital based on timesheets and other information provided to the Parent Hospital by the Rotation Hospital.</p><p><strong>24.9</strong> Provided that where the arrangement at subclause 24.8(a) above is effected, service and the accrual of leave will continue unaffected with the Parent Hospital, subject to appropriate reductions for accrued entitlements utilised or the occasion of unpaid leave that would normally affect service.</p><p>Plain language terms: hospital rotation.</p>',23)])])}const g=e(i,[["render",r]]);export{m as __pageData,g as default};
